INSERT INTO reviews (id, booking_id, company_id, customer_id, service_type, rating, title, comment, criteria, status, is_verified, helpful_count, created_at, updated_at) VALUES ('70086390-ad28-475f-8d64-c65c79c23a41', '21babcfe-3a59-40dd-b331-6cf47c9a96a6', '5f79619e-f8eb-4e47-8ce8-e76753b22380', 'd818881b-fed2-444e-b478-a3d925dd0ff0', 'HOTEL', 5, 'Outstanding service', 'Great location, close to all major attractions. The breakfast was delicious and the pool area was beautiful. Highly recommend this hotel.', '{\"cleanliness\":5,\"comfort\":5,\"service\":5,\"amenities\":5,\"valueForMoney\":5,\"location\":5}', 'APPROVED', 1, 12, '2025-09-04 16:37:39', '2025-09-04 16:37:39');
INSERT INTO reviews (id, booking_id, company_id, customer_id, service_type, rating, title, comment, criteria, status, is_verified, helpful_count, created_at, updated_at) VALUES ('ee62ad54-3ef9-454a-b943-99a7a6bd766f', 'bd2829f0-d2f2-4ad7-8a9a-3fab2915240a', '5f79619e-f8eb-4e47-8ce8-e76753b22380', '42a53456-a512-4ae4-97be-71554838a362', 'HOTEL', 5, 'Loved it!', 'Excellent service from check-in to check-out. The concierge was very helpful with recommendations. The room had a beautiful view.', '{\"cleanliness\":5,\"comfort\":5,\"service\":5,\"amenities\":5,\"valueForMoney\":5,\"location\":5}', 'APPROVED', 1, 26, '2026-01-01 17:37:39', '2026-01-01 17:37:39');
INSERT INTO reviews (id, booking_id, company_id, customer_id, service_type, rating, title, comment, criteria, status, is_verified, helpful_count, created_at, updated_at) VALUES ('0c297709-4bea-456f-8d8c-60b1357f9729', 'ae26e2bb-d4cd-4c2c-b41b-f6144208cd9c', '5f79619e-f8eb-4e47-8ce8-e76753b22380', '933151cc-6148-4cf9-84aa-cdfe2708f891', 'HOTEL', 1, 'Average hotel', 'Disappointing stay. The room was not as advertised. Several maintenance issues. Staff tried to help but couldn't resolve all problems.', '{\"cleanliness\":1,\"comfort\":1,\"service\":1,\"amenities\":1,\"valueForMoney\":1,\"location\":1}', 'APPROVED', 1, 14, '2025-11-11 17:37:39', '2025-11-11 17:37:39');
INSERT INTO reviews (id, booking_id, company_id, customer_id, service_type, rating, title, comment, criteria, status, is_verified, helpful_count, created_at, updated_at) VALUES ('118da7f7-d79c-49a0-92a7-b2670966e0d8', '6b5fb6bd-42de-40bb-b086-d15f9f5b8923', '5f79619e-f8eb-4e47-8ce8-e76753b22380', 'a72e2eb5-27ee-4b60-88cf-a871bc01fb82', 'HOTEL', 5, 'Wonderful stay', 'Beautiful hotel with great facilities. The gym was well-equipped and the spa was relaxing. Room service was prompt and delicious.', '{\"cleanliness\":5,\"comfort\":5,\"service\":5,\"amenities\":5,\"valueForMoney\":5,\"location\":5}', 'APPROVED', 1, 24, '2025-08-23 16:37:39', '2025-08-23 16:37:39');
